const QUESTIONS_CPENT_C1 = [
  { id:90101, domain:1, level:1, question:"Which penetration testing standard is organized into seven phases beginning with pre-engagement interactions?", options:["The Penetration Testing Execution Standard defines seven phases from pre-engagement through reporting","The OWASP Testing Guide focuses only on web application security controls and coverage checklists here","OSSTMM measures operational security across channels but does not use the seven named PTES phases","NIST SP 800-115 is a technical guide to information security testing rather than a seven-phase model"], correct:0, explanation:"PTES defines seven phases; OSSTMM measures operational security via channels, not the PTES phases." },
  { id:90102, domain:1, level:2, question:"Which document provides a technical guide to information security testing and assessment published by NIST?", options:["NIST SP 800-53 catalogs security and privacy controls rather than describing testing procedures used","NIST SP 800-115 is the technical guide to information security testing and assessment for organizations","PCI DSS is a payment card industry compliance standard, not a NIST testing publication for assessors","ISO 27001 specifies an information security management system framework, not a testing methodology guide"], correct:1, explanation:"SP 800-115 is the NIST testing guide; SP 800-53 is a controls catalog, not a testing guide." },
  { id:90103, domain:1, level:3, question:"What does the OSSTMM methodology primarily measure?", options:["Only the compliance status of an organization against PCI DSS payment card processing requirements here","Only the source code quality of the custom web applications that are built within the enterprise itself","Operational security across channels such as human, physical, wireless, and data network communications","Only the physical security of data center facilities along with their badge-based access control systems"], correct:2, explanation:"OSSTMM measures operational security across multiple channels, not solely PCI compliance." },
  { id:90104, domain:1, level:2, question:"Which framework is most associated with web application security categories like injection and broken access control?", options:["NIST SP 800-115, which is a general technical testing guide spanning many domains beyond web applications","MITRE ATT&CK, which catalogs adversary tactics and techniques observed during post-compromise activity","OSSTMM, which measures operational security across communication channels rather than web application flaws","The OWASP Testing Guide and OWASP Top 10 focus specifically on web application security risks and testing"], correct:3, explanation:"OWASP centers on web app risks; MITRE ATT&CK catalogs adversary behavior instead." },
  { id:90105, domain:1, level:3, question:"An organization wants a repeatable, metrics-driven methodology to measure operational security. Which fits best?", options:["OSSTMM, because it emphasizes measurable operational security testing across defined channels and vectors","The OWASP Top 10, because it ranks the ten most critical web risks but offers no operational metrics model","A CVSS score sheet, because it rates individual vulnerabilities but is not a full testing methodology itself","A generic checklist of firewall rules, because it documents configuration rather than measured security state"], correct:0, explanation:"OSSTMM is metrics-driven across channels; the OWASP Top 10 is a web risk ranking, not an ops metric model." },
  { id:90106, domain:1, level:2, question:"In which testing approach does the tester have no prior knowledge of the target environment?", options:["White box testing, in which full source code and detailed architecture documentation are provided upfront","Black box testing, in which the tester begins with no internal knowledge of the target under assessment","Gray box testing, in which the tester is given partial internal knowledge of the target before starting","Crystal box testing, in which every configuration value and credential is shared with the tester in advance"], correct:1, explanation:"Black box means no prior knowledge; white box provides full internal details to the tester." },
  { id:90107, domain:1, level:1, question:"Which test type gives the tester full internal knowledge including source code and network diagrams?", options:["Black box testing provides no internal knowledge and simulates an outside attacker with no documentation","Gray box testing provides only partial internal knowledge to the assessment team during the engagement in this context","White box testing provides complete internal knowledge such as source code and architecture diagrams to use","Blind testing provides the tester with only the organization name and nothing else to begin the work with"], correct:2, explanation:"White box provides full knowledge; black box provides none." },
  { id:90108, domain:1, level:2, question:"Which test simulates an attacker who has some limited internal knowledge, such as user-level credentials?", options:["Black box testing, which assumes absolutely no knowledge whatsoever of the internal target environment in this context","White box testing, which assumes complete knowledge of both source code and the underlying infrastructure","Double-blind testing, in which neither the testers nor the defenders know the schedule of the engagement","Gray box testing, which combines limited internal knowledge with realistic external attack techniques used"], correct:3, explanation:"Gray box means partial knowledge; black box assumes none." },
  { id:90109, domain:1, level:3, question:"An engagement conducted from outside the organization's network perimeter is best described as what?", options:["An external penetration test targeting internet-facing assets from outside the organization's perimeter edge","An internal penetration test that instead starts from a position already located inside the local network","A physical penetration test that is focused primarily on bypassing building and facility access controls","A social engineering test that is focused solely on phishing the organization's employees through email in this context"], correct:0, explanation:"External tests target internet-facing assets; internal tests originate inside the LAN." },
  { id:90110, domain:1, level:2, question:"A test that begins from a foothold already inside the corporate LAN is called what?", options:["An external penetration test that is launched entirely from the public internet against perimeter systems","An internal penetration test, which simulates a malicious insider or a breached internal workstation host","A red team exercise that is strictly limited to open-source intelligence gathering and nothing else at all","A compliance audit that only reviews documented policy artifacts rather than any live production systems"], correct:1, explanation:"Internal tests start inside the LAN; external tests start from the internet." },
  { id:90111, domain:1, level:3, question:"A firm wants testers to simulate a phishing-based breach starting from a compromised employee laptop. This is closest to which scenario?", options:["A pure black box external test, since the tester would begin entirely from the internet with no access yet","A vulnerability assessment, since the goal is only to list weaknesses without ever exploiting any of them","An assumed-breach internal test, since the tester begins from an already-compromised internal foothold host","A physical penetration test, since the primary objective is to bypass the building's physical access controls"], correct:2, explanation:"Assumed-breach starts from an internal foothold; a black box external test starts from the internet with no access." },
  { id:90112, domain:1, level:2, question:"Which document formally authorizes testers to perform attacks and defines what is in scope?", options:["A marketing brochure describing the security vendor's various service offerings along with their pricing","The final penetration test report, which is only delivered after all of the testing has been completed","The vulnerability scanner's default configuration file that happens to be used during the assessment work","The Rules of Engagement, which define the scope, timing, permitted methods, and authorization limits used"], correct:3, explanation:"RoE define scope and authorization; the final report is produced after testing." },
  { id:90113, domain:1, level:1, question:"What is the primary purpose of a Statement of Work in a penetration test?", options:["To define the scope, deliverables, timeline, and objectives of the engagement between both of the parties","To provide law enforcement with a warrant that allows them to seize the client's computing equipment in this context","To list every single known vulnerability present in the target before any testing has even started yet","To completely replace the need for any written authorization coming from the client's own organization"], correct:0, explanation:"The SOW defines scope and deliverables; it is not a warrant or a vuln list." },
  { id:90114, domain:1, level:2, question:"Which agreement protects confidential information shared between the client and the testing team?", options:["A get-out-of-jail-free letter, which instead authorizes the specific testing activities against systems","A Non-Disclosure Agreement, which legally protects the confidential information exchanged by both parties","A Statement of Work, which primarily defines the deliverables and overall timeline of the engagement work","A service level agreement, which only specifies the uptime guarantees for the client's production systems"], correct:1, explanation:"An NDA protects confidentiality; authorization is a separate document." },
  { id:90115, domain:1, level:3, question:"What is the purpose of a written authorization or 'get-out-of-jail-free' letter?", options:["To guarantee that the tester will never once trigger any intrusion detection alerts during the engagement","To permanently transfer all liability for any data loss onto the client organization no matter the cause in this context","To provide legal proof that the client explicitly authorized the specific testing activities being performed","To exempt the tester from having to follow the agreed scope and the documented rules of engagement at all"], correct:2, explanation:"It proves authorization; it does not exempt testers from the agreed scope." },
  { id:90116, domain:1, level:2, question:"Why should scope boundaries and IP ranges be confirmed in writing before testing begins?", options:["To ensure the tester is free to attack any third-party cloud provider systems without seeking permission","To eliminate the need to produce any report at all once the assessment has been fully completed and closed","To allow the tester to skip reconnaissance entirely and move directly into the exploitation phase of work","To avoid testing any systems that the client does not own or has not explicitly authorized for the testing"], correct:3, explanation:"Confirming scope prevents testing unauthorized or third-party systems." },
  { id:90117, domain:1, level:3, question:"A client's web app is hosted on a third-party cloud provider. What must the tester obtain before testing it?", options:["Authorization from the cloud provider in addition to the client, as required by that provider's own policies","Nothing extra at all, because the client's own authorization always fully covers every hosting provider used","Only a quick verbal agreement from the client's help desk staff before beginning the exploitation activities","A signed NDA on its own, which by itself is enough to grant full permission to attack the cloud-hosted assets"], correct:0, explanation:"Cloud providers often require their own authorization; client consent alone is insufficient." },
  { id:90118, domain:1, level:2, question:"During testing, the tester realizes an in-scope IP actually belongs to a neighboring company. What is the correct action?", options:["Continue testing the IP anyway, because it was listed in the original scope document that the client provided","Stop testing that IP immediately and confirm ownership and authorization with the client before continuing on","Quietly exploit the host first and then ask the client about the ownership question afterward during reporting","Ignore the discrepancy entirely and simply avoid mentioning the neighboring company anywhere in the final report"], correct:1, explanation:"Testing systems the client does not own is unauthorized; stop and confirm ownership first." },
  { id:90119, domain:1, level:1, question:"Which phase of a penetration test involves defining scope, goals, and rules of engagement?", options:["The exploitation phase, during which the identified vulnerabilities are actively leveraged against systems","The reporting phase, during which the findings and recommendations are documented and delivered to clients","The pre-engagement phase, during which the scope, goals, and rules of engagement are formally established","The post-exploitation phase, during which persistence and lateral movement across the network are attempted"], correct:2, explanation:"Pre-engagement sets scope and RoE; exploitation happens later." },
  { id:90120, domain:1, level:2, question:"Gathering information about a target without directly interacting with its systems is called what?", options:["Active reconnaissance, which instead sends packets and probes directly to the target's systems and services","Exploitation, which leverages a previously discovered vulnerability in order to gain access to a system host","Privilege escalation, which raises the level of access from a normal user account up to an administrator one","Passive reconnaissance, which collects information about a target without ever touching that target directly"], correct:3, explanation:"Passive recon avoids direct contact; active recon probes the target." },
  { id:90121, domain:1, level:3, question:"Which activity is an example of active reconnaissance?", options:["Running an Nmap port scan that sends packets directly to the target host to enumerate its listening services","Reviewing a company's public LinkedIn profiles in order to enumerate the names of its current employees in this context","Searching public WHOIS records to find domain registration and administrative contact information details","Reading cached search-engine results describing the organization's publicly known technology stack choices"], correct:0, explanation:"Nmap scanning contacts the target (active); WHOIS and LinkedIn review are passive." },
  { id:90122, domain:1, level:2, question:"OSINT stands for which of the following?", options:["Operational Security Intelligence Network, which would be an internal monitoring platform used by SOC teams","Open Source Intelligence, which is intelligence gathered from publicly available information sources online","Offensive Security Intrusion Nomenclature, which would be a formal taxonomy of exploitation techniques used","Online System Integrity Notification, which would be an alerting service tied to enterprise patch management"], correct:1, explanation:"OSINT stands for Open Source Intelligence gathered from public sources." },
  { id:90123, domain:1, level:3, question:"Footprinting a target primarily aims to accomplish what?", options:["Immediately exploiting a discovered vulnerability in order to obtain a remote interactive shell on the host","Encrypting the target's stored data in order to demonstrate the impact of a hypothetical ransomware attack overall","Building a profile of the target's systems, domains, employees, and technologies before deeper testing begins","Deleting the audit logs on compromised systems so as to hide the tester's activities from the defenders team"], correct:2, explanation:"Footprinting builds a target profile; it does not exploit or encrypt anything." },
  { id:90124, domain:1, level:2, question:"Which phase typically directly follows successful exploitation in a penetration test?", options:["Pre-engagement, where the scope and the rules of engagement for the entire assessment are first established","Passive reconnaissance, where information is collected without any direct interaction with target systems yet","Initial scoping, where the client and the tester agree on the objectives long before any testing has started","Post-exploitation, where the tester assesses impact, escalates privileges, and pursues lateral movement paths"], correct:3, explanation:"Post-exploitation follows exploitation; pre-engagement and scoping happen first." },
  { id:90125, domain:1, level:1, question:"In the penetration testing lifecycle, why is the reporting phase considered as important as exploitation?", options:["Because clear reporting translates technical findings into actionable, prioritized remediation for the client","Because reporting is the only phase where the tester is legally allowed to run any exploits against systems overall","Because reporting removes the requirement to ever obtain written authorization prior to any testing activity","Because reporting automatically patches the discovered vulnerabilities before the client reads the document"], correct:0, explanation:"Reporting delivers actionable remediation value; it does not run exploits or auto-patch anything." },
  { id:90126, domain:1, level:2, question:"Which Nmap option performs a TCP SYN (half-open) scan?", options:["The -sU option performs a UDP scan of the target rather than a TCP SYN half-open scan of its open ports","The -sS option performs a stealthy TCP SYN half-open scan against the specified target ports and services","The -sn option performs only host discovery and deliberately skips scanning any of the target's TCP ports","The -O option enables operating system detection but does not by itself open or probe any TCP ports at all"], correct:1, explanation:"-sS is a SYN scan; -sU is UDP, -sn is a ping sweep, and -O is OS detection." },
  { id:90127, domain:1, level:3, question:"Which Nmap flag enables operating system detection?", options:["The -sV flag instead enables service and version detection rather than any operating system fingerprinting overall","The -p flag simply specifies which ports should be scanned and does not attempt to detect the OS by itself","The -O flag enables Nmap operating system fingerprinting based on observed TCP/IP stack behavior of the host","The -A flag on its own only enables aggressive timing options without turning on the OS detection features"], correct:2, explanation:"-O is OS detection; -sV is service version detection." },
  { id:90128, domain:1, level:2, question:"Which Nmap option attempts to determine the version of services running on open ports?", options:["The -sn option performs only host discovery and therefore never probes any service versions on the target","The -Pn option skips the host discovery step and simply assumes that all specified hosts are already online","The -f option fragments the outgoing packets to attempt evasion of certain packet-filtering firewall rules","The -sV option performs service and version detection against each of the discovered open ports on the host"], correct:3, explanation:"-sV performs version detection; -sn only does host discovery." },
  { id:90129, domain:1, level:3, question:"Connecting to an open port to read the service's identifying response text is called what?", options:["Banner grabbing, which reads the service banners returned in order to identify the software and its version","Fuzzing, which instead sends malformed or unexpected input to try to trigger crashes or abnormal behavior","Pivoting, which routes further attacks through a compromised host in order to reach other internal systems","Sniffing, which passively captures the network traffic that happens to be traversing a shared media segment"], correct:0, explanation:"Banner grabbing reads service banners; fuzzing sends malformed input." },
  { id:90130, domain:1, level:2, question:"What is the main goal of the enumeration phase?", options:["To write the final executive summary that ranks all of the findings strictly by their overall business risk","To extract detailed information such as usernames, network shares, and running services from the target hosts","To obtain the signed legal authorization from the client that must exist before any testing may even begin overall","To physically inspect the data center server racks looking for any unauthorized hardware devices installed"], correct:1, explanation:"Enumeration extracts detailed info like users and shares; authorization is pre-engagement." },
  { id:90131, domain:1, level:1, question:"Which Nmap option skips host discovery and treats all listed hosts as online?", options:["The -sV option instead performs service and version detection and does not change host discovery behavior","The -O option performs operating system fingerprinting and has no effect on the host discovery ping stage","The -Pn option tells Nmap to skip the host discovery step and to treat every specified host as being online","The -sn option performs only host discovery and is essentially the opposite of skipping that same stage now"], correct:2, explanation:"-Pn skips host discovery; -sn does host discovery only, its opposite." },
  { id:90132, domain:1, level:2, question:"A firewall drops ICMP, so Nmap reports all hosts as down. Which option best addresses this?", options:["Use -sn so that Nmap performs only host discovery, which would still fail because ICMP is being dropped now","Use -O so that Nmap performs OS detection, which does not resolve the underlying host discovery ping problem","Use -sU to switch to a UDP scan, which does not change how Nmap decides whether a host is up during discovery","Use -Pn so Nmap skips ICMP-based host discovery and proceeds to scan the hosts as though they were online"], correct:3, explanation:"-Pn bypasses the failing ICMP discovery; -sn would still rely on the blocked discovery step." },
  { id:90133, domain:1, level:3, question:"What is the key difference between a vulnerability assessment and a penetration test?", options:["A penetration test exploits vulnerabilities to demonstrate impact, whereas an assessment only identifies them","A vulnerability assessment always exploits each finding, whereas a penetration test merely lists them out","There is genuinely no difference at all, since the two terms are fully interchangeable in every context in this context","A penetration test never uses any automated scanners, which is unlike a typical vulnerability assessment"], correct:0, explanation:"Pen tests exploit to prove impact; assessments identify but do not exploit." },
  { id:90134, domain:1, level:2, question:"A vulnerability assessment primarily produces which of the following?", options:["A fully working exploit chain that completely compromises the domain controller of the target environment","A prioritized list of the identified weaknesses in the environment, typically without exploiting any of them","A signed contract that authorizes the scope and the timing of some future penetration testing engagement in this context","A formal criminal referral submitted to law enforcement for the prosecution of the responsible attackers"], correct:1, explanation:"Assessments list weaknesses without exploitation." },
  { id:90135, domain:1, level:3, question:"A client with very low security maturity asks whether to start with a vulnerability assessment or a pen test. What is generally advised?", options:["Start immediately with a full red team engagement, since that always reveals the most value the very fastest overall","Skip both entirely and just purchase more firewalls, since tooling alone reliably removes the underlying risk","Start with a vulnerability assessment, since immature environments usually have many basic issues to fix first","Start with exploitation of production systems, since breaking things is the only way to truly prove any risk"], correct:2, explanation:"Low-maturity orgs benefit from an assessment to fix basics first; jumping to red teaming is premature." },
  { id:90136, domain:1, level:2, question:"What is the primary purpose of threat modeling in a penetration test?", options:["To generate the final invoice for the engagement based strictly on the number of hours that were worked here","To automatically patch every discovered vulnerability well before the final report is ever written for anyone","To completely replace reconnaissance by simply guessing which of the target's ports are most likely to be open","To identify likely attackers, valuable assets, and probable attack paths so that testing effort is prioritized"], correct:3, explanation:"Threat modeling identifies threats, assets, and paths; it does not patch or invoice." },
  { id:90137, domain:1, level:1, question:"What does the MITRE ATT&CK framework primarily catalog?", options:["Adversary tactics, techniques, and procedures that have been observed across real-world attacks and campaigns","A prioritized list of software patches that are ranked strictly by their calculated CVSS base severity scores","A set of ready-made legal templates used for authorizing penetration testing engagements safely and quickly","A commercial pricing model comparing vulnerability scanners along with each of their support and license tiers"], correct:0, explanation:"ATT&CK catalogs adversary TTPs, not patches or contracts." },
  { id:90138, domain:1, level:2, question:"In MITRE ATT&CK, 'Lateral Movement' is best described as what kind of category?", options:["A specific software tool that is designed to automatically exploit every single host on the local subnet at once","A tactic representing the adversary's goal of moving through the environment to reach additional systems there","A compliance control that is mandated by PCI DSS for the segmentation of cardholder data networks in scope","A reporting template that is used to summarize the assessment findings for executive-level stakeholders reading"], correct:1, explanation:"In ATT&CK, tactics are adversary goals like Lateral Movement; techniques are the specific how." },
  { id:90139, domain:1, level:3, question:"How can the MITRE ATT&CK framework help during a penetration test?", options:["It automatically writes the entire final report so the tester does not have to document any findings by hand","It legally authorizes the tester to attack the client without requiring any separate signed permission document","It provides a common language for mapping observed techniques and for planning realistic adversary emulation","It replaces the need for reconnaissance because it lists the exact open ports on every possible target system"], correct:2, explanation:"ATT&CK gives a shared technique language for emulation; it does not authorize or auto-report." },
  { id:90140, domain:1, level:2, question:"Which report section is written primarily for non-technical business leadership?", options:["The technical findings appendix, which lists the raw scanner output along with captured packet data for review","The methodology section, which details the exact commands and the specific tools that the tester actually ran","The scope statement, which enumerates each of the authorized IP addresses and hostnames included in the test","The executive summary, which conveys the overall business risk and impact using clear non-technical language"], correct:3, explanation:"The executive summary targets leadership; technical detail goes in other sections." },
  { id:90141, domain:1, level:3, question:"Why should a penetration test report include remediation recommendations?", options:["To help the client fix the identified issues and thereby reduce their risk after the engagement has concluded","To guarantee that the very same vulnerabilities can never once possibly be reintroduced by anyone ever again","To satisfy a legal requirement stating that all reports must transfer full liability onto the testing party","To ensure that the report is simply long enough to justify the total price that was charged to the client for the target"], correct:0, explanation:"Remediation guidance helps clients fix issues; it cannot guarantee permanence." },
  { id:90142, domain:1, level:2, question:"How should vulnerabilities in a report typically be prioritized for the client?", options:["Alphabetically by the name of each affected host, simply to make the overall finding list easier to scan","By risk, taking into account both technical severity and business impact to guide the remediation ordering","By the chronological order in which the tester happened to first discover each of the individual issues in this context","Randomly, so that the client is encouraged to review every finding with an equal amount of care attention"], correct:1, explanation:"Findings are prioritized by risk and impact, not alphabetically or randomly." },
  { id:90143, domain:1, level:1, question:"A critical vulnerability is discovered mid-engagement that is actively being exploited. What is the best reporting practice?", options:["Wait until the scheduled final report so all of the findings can be presented together in a single document","Post the details to a public forum first so that the wider security community is warned before the client is","Notify the client immediately out of band rather than waiting until the final report is delivered at the end","Omit the finding from the report entirely to avoid alarming the client's executive leadership team unduly"], correct:2, explanation:"Critical, actively-exploited findings warrant immediate out-of-band notification, not waiting for the report." },
  { id:90144, domain:1, level:2, question:"What should an ethical penetration tester do upon discovering evidence of a prior real breach?", options:["Continue the testing and delete the evidence found in order to keep the engagement scope on its set schedule","Publicly disclose the breach on social media in order to warn the potentially affected customers right away","Exploit the existing attacker backdoor even further just to see how far the intruder had already managed to go","Stop, preserve the available evidence, and immediately notify the client following the agreed procedures used"], correct:3, explanation:"Testers must stop, preserve evidence, and notify the client, not tamper or publicly disclose." },
  { id:90145, domain:1, level:3, question:"Which behavior best reflects professionalism during a penetration test?", options:["Staying within the authorized scope while reporting all of the findings both accurately and honestly to clients","Expanding the agreed scope on the fly whenever some interesting out-of-scope system happens to be discovered","Exaggerating the severity of the findings in order to make the overall engagement appear far more valuable overall","Withholding the most critical findings from the client until a follow-up contract has been completely signed"], correct:0, explanation:"Professionalism means staying in scope and reporting honestly." },
  { id:90146, domain:1, level:2, question:"A tester is offered a bonus by an employee to omit that employee's server from the report. What is the ethical response?", options:["Accept the bonus quietly and omit the server, since it only affects one host and no one else will ever notice","Decline the offer and report the finding accurately, since integrity and honesty are core to the profession","Omit the server but mention it verbally later, since a spoken note is an acceptable substitute for reporting","Report only half of the affected servers as a reasonable compromise between the offer and the tester's duty"], correct:1, explanation:"Integrity requires declining and reporting accurately; omitting findings for a bribe is unethical." },
  { id:90147, domain:1, level:3, question:"Which Linux distribution is purpose-built for penetration testing with many security tools preinstalled?", options:["Windows Server, which is a general-purpose enterprise operating system used mainly for hosting services here","Ubuntu Desktop, which is a general-purpose Linux distribution aimed primarily at everyday desktop end users","Kali Linux, which is a Debian-based distribution designed specifically for penetration testing and forensics","macOS, which is Apple's proprietary desktop operating system built to run only on its own hardware platforms"], correct:2, explanation:"Kali is purpose-built for pen testing; the others are general-purpose operating systems." },
  { id:90148, domain:1, level:2, question:"In the Metasploit Framework, what is a 'payload'?", options:["The vulnerability scanner that catalogs the open ports on the target before any exploitation has yet begun here","The legal document that authorizes the tester to run the various exploits against the target host in question","The report template that neatly summarizes the assessment findings for the client's leadership team afterward","The code executed on a target after a successful exploit, such as a reverse shell or a Meterpreter session"], correct:3, explanation:"A payload is the post-exploit code; an exploit delivers it to the target." },
  { id:90149, domain:1, level:1, question:"In Metasploit, what does the 'exploit' component do?", options:["It takes advantage of a specific vulnerability in order to deliver the chosen payload onto the target system","It encrypts all of the tester's network traffic so that the intrusion detection system cannot observe any of it","It generates the final PDF report automatically at the very conclusion of the assessment engagement for clients","It only enumerates the target's usernames and never actually interacts with any vulnerability during its run"], correct:0, explanation:"The exploit leverages a vulnerability to deliver the payload." },
  { id:90150, domain:1, level:2, question:"Which tool is primarily used for network port scanning and host discovery?", options:["Wireshark, which is used primarily as a passive packet capture and network protocol analyzer application tool","Nmap, which is a widely used tool for network port scanning, host discovery, and service version detection work","John the Ripper, which is used primarily as a password-cracking tool that targets hashed credential material overall","Burp Suite, which is used primarily as an intercepting proxy for the testing of web application security flaws"], correct:1, explanation:"Nmap does scanning and discovery; Wireshark captures packets rather than scanning." },
  { id:90151, domain:1, level:3, question:"Which tool is an intercepting proxy commonly used for web application penetration testing?", options:["Nmap, which performs network port scanning of hosts rather than intercepting any HTTP requests or responses","Aircrack-ng, which is a software suite focused specifically on wireless network security assessment tasks","Burp Suite, which is an intercepting proxy used to analyze and manipulate web application traffic in transit","Hashcat, which is a high-speed password recovery utility that cracks hashes rather than proxying web traffic"], correct:2, explanation:"Burp Suite intercepts web traffic; Nmap scans ports." },
  { id:90152, domain:1, level:2, question:"Which tool is primarily used to capture and analyze network packets?", options:["Metasploit, which is an exploitation framework used mainly to deliver payloads against vulnerable target hosts","Nikto, which is a web server scanner that looks for dangerous files and outdated software on web servers only","Hydra, which is an online password brute-forcing tool that targets authentication services over the network","Wireshark, which is a graphical packet capture and protocol analysis tool used to inspect network traffic here"], correct:3, explanation:"Wireshark captures and analyzes packets; Metasploit is for exploitation." },
  { id:90153, domain:1, level:3, question:"Which tool is commonly used for offline password hash cracking?", options:["John the Ripper, which is a widely used tool for cracking captured password hashes in an offline manner here","Nmap, which is used for network port scanning and host discovery rather than for any password cracking work","Wireshark, which is used for packet capture and analysis and does not perform offline hash cracking at all","Burp Suite, which is an intercepting web proxy and is not primarily designed for offline hash cracking tasks"], correct:0, explanation:"John the Ripper cracks hashes; Nmap scans networks." },
  { id:90154, domain:1, level:2, question:"Which service most commonly listens on default TCP port 21?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 21 by default","FTP, which conventionally listens on TCP port 21 in most standard default deployments today","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 21 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 21 in real practice"], correct:1, explanation:"Port 21 conventionally maps to FTP; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90155, domain:1, level:1, question:"Which service most commonly listens on default TCP port 22?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 22 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 22 here","SSH, which conventionally listens on TCP port 22 in most standard default deployments today","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 22 in real practice"], correct:2, explanation:"Port 22 conventionally maps to SSH; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90156, domain:1, level:2, question:"Which service most commonly listens on default TCP port 23?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 23 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 23 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 23 in real practice","Telnet, which conventionally listens on TCP port 23 in most standard default deployments today"], correct:3, explanation:"Port 23 conventionally maps to Telnet; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90157, domain:1, level:3, question:"Which service most commonly listens on default TCP port 25?", options:["SMTP, which conventionally listens on TCP port 25 in most standard default deployments today","DHCP, which is a UDP-based address assignment service and does not use TCP port 25 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 25 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 25 in real practice"], correct:0, explanation:"Port 25 conventionally maps to SMTP; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90158, domain:1, level:2, question:"Which service most commonly listens on default TCP port 53?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 53 by default","DNS, which conventionally listens on TCP port 53 in most standard default deployments today","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 53 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 53 in real practice"], correct:1, explanation:"Port 53 conventionally maps to DNS; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90159, domain:1, level:3, question:"Which service most commonly listens on default TCP port 80?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 80 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 80 here","HTTP, which conventionally listens on TCP port 80 in most standard default deployments today","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 80 in real practice"], correct:2, explanation:"Port 80 conventionally maps to HTTP; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90160, domain:1, level:2, question:"Which service most commonly listens on default TCP port 110?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 110 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 110 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 110 in real practice","POP3, which conventionally listens on TCP port 110 in most standard default deployments today"], correct:3, explanation:"Port 110 conventionally maps to POP3; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90161, domain:1, level:1, question:"Which service most commonly listens on default TCP port 135?", options:["MSRPC, which conventionally listens on TCP port 135 in most standard default deployments today","DHCP, which is a UDP-based address assignment service and does not use TCP port 135 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 135 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 135 in real practice"], correct:0, explanation:"Port 135 conventionally maps to MSRPC; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90162, domain:1, level:2, question:"Which service most commonly listens on default TCP port 139?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 139 by default during the engagement","NetBIOS Session Service, which conventionally listens on TCP port 139 in most standard default deployments today","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 139 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 139 in real practice"], correct:1, explanation:"Port 139 conventionally maps to NetBIOS Session Service; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90163, domain:1, level:3, question:"Which service most commonly listens on default TCP port 143?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 143 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 143 here","IMAP, which conventionally listens on TCP port 143 in most standard default deployments today","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 143 in real practice"], correct:2, explanation:"Port 143 conventionally maps to IMAP; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90164, domain:1, level:2, question:"Which service most commonly listens on default TCP port 161?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 161 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 161 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 161 in real practice","SNMP, which conventionally listens on TCP port 161 in most standard default deployments today"], correct:3, explanation:"Port 161 conventionally maps to SNMP; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90165, domain:1, level:3, question:"Which service most commonly listens on default TCP port 389?", options:["LDAP, which conventionally listens on TCP port 389 in most standard default deployments today","DHCP, which is a UDP-based address assignment service and does not use TCP port 389 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 389 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 389 in real practice"], correct:0, explanation:"Port 389 conventionally maps to LDAP; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90166, domain:1, level:2, question:"Which service most commonly listens on default TCP port 443?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 443 by default","HTTPS, which conventionally listens on TCP port 443 in most standard default deployments today","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 443 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 443 in real practice"], correct:1, explanation:"Port 443 conventionally maps to HTTPS; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90167, domain:1, level:1, question:"Which service most commonly listens on default TCP port 445?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 445 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 445 here","SMB, which conventionally listens on TCP port 445 in most standard default deployments today","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 445 in real practice"], correct:2, explanation:"Port 445 conventionally maps to SMB; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90168, domain:1, level:2, question:"Which service most commonly listens on default TCP port 1433?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 1433 by default in this context","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 1433 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 1433 in real practice","Microsoft SQL Server, which conventionally listens on TCP port 1433 in most standard default deployments today"], correct:3, explanation:"Port 1433 conventionally maps to Microsoft SQL Server; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90169, domain:1, level:3, question:"Which service most commonly listens on default TCP port 3306?", options:["MySQL, which conventionally listens on TCP port 3306 in most standard default deployments today","DHCP, which is a UDP-based address assignment service and does not use TCP port 3306 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 3306 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 3306 in real practice"], correct:0, explanation:"Port 3306 conventionally maps to MySQL; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90170, domain:1, level:2, question:"Which service most commonly listens on default TCP port 3389?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 3389 by default","RDP, which conventionally listens on TCP port 3389 in most standard default deployments today","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 3389 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 3389 in real practice"], correct:1, explanation:"Port 3389 conventionally maps to RDP; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90171, domain:1, level:3, question:"Which service most commonly listens on default TCP port 5432?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 5432 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 5432 here","PostgreSQL, which conventionally listens on TCP port 5432 in most standard default deployments today","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 5432 in real practice"], correct:2, explanation:"Port 5432 conventionally maps to PostgreSQL; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90172, domain:1, level:2, question:"Which service most commonly listens on default TCP port 8080?", options:["DHCP, which is a UDP-based address assignment service and does not use TCP port 8080 by default during the engagement","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 8080 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 8080 in real practice","alternate HTTP web service, which conventionally listens on TCP port 8080 in most standard default deployments today"], correct:3, explanation:"Port 8080 conventionally maps to alternate HTTP web service; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90173, domain:1, level:1, question:"Which service most commonly listens on default TCP port 6379?", options:["Redis, which conventionally listens on TCP port 6379 in most standard default deployments today","DHCP, which is a UDP-based address assignment service and does not use TCP port 6379 by default","NTP, which synchronizes clocks over UDP and is not the standard service found on TCP port 6379 here","TFTP, which is a UDP-based trivial file transfer service unrelated to TCP port 6379 in real practice"], correct:0, explanation:"Port 6379 conventionally maps to Redis; DHCP, NTP, and TFTP are UDP-based and unrelated." },
  { id:90174, domain:1, level:2, question:"What is the primary goal of the pre-engagement phase?", options:["To immediately begin exploiting the discovered vulnerabilities on the target's production systems right away overall","To agree on scope, objectives, timelines, and rules of engagement before any active testing takes place at all","To draft the final report and deliver it to the client before any of the technical testing has been done yet","To physically install monitoring hardware inside the client's data center racks prior to the assessment work"], correct:1, explanation:"Pre-engagement agrees scope and RoE; exploitation and reporting come later." },
  { id:90175, domain:1, level:3, question:"What distinguishes passive OSINT from active reconnaissance?", options:["Passive OSINT always requires exploiting a live vulnerability, unlike active recon which never touches any host","Passive OSINT is illegal in every jurisdiction, while active reconnaissance is universally permitted anywhere overall","Passive OSINT uses public sources without touching the target, while active recon sends probes to the target host","Passive OSINT only works against wireless networks, while active recon only works against wired networks here"], correct:2, explanation:"Passive OSINT avoids contact; active recon probes the target directly." },
  { id:90176, domain:1, level:2, question:"What is the purpose of a scoping call before an engagement?", options:["To immediately crack the client's Active Directory passwords before the contract has even been signed at all","To publicly announce the upcoming test on social media so that the client's competitors are made fully aware","To bypass the requirement for written authorization by substituting a quick and informal phone conversation overall","To clarify targets, constraints, timing, and success criteria so the engagement is well defined for both sides"], correct:3, explanation:"Scoping clarifies targets and constraints; it never replaces written authorization." },
  { id:90177, domain:1, level:3, question:"Why is written authorization essential before any testing?", options:["Because unauthorized access to computer systems is illegal, and authorization provides the necessary legal basis","Because authorization guarantees the tester can never accidentally cause any downtime on production systems overall","Because authorization automatically indemnifies the tester against every possible outcome of the engagement","Because authorization removes the need to define any scope, since the tester may then test whatever they wish"], correct:0, explanation:"Authorization provides the legal basis; it does not remove scope or guarantee no downtime." },
  { id:90178, domain:1, level:2, question:"What is the main risk of testing outside the agreed scope?", options:["It always improves the quality of the final report by uncovering many additional and highly valuable findings","It may constitute unauthorized access, exposing the tester to legal liability and damaging client trust badly","It is encouraged because more coverage is always strictly better regardless of what was actually authorized","It has no real consequences as long as the tester documents the extra activity somewhere in the final report"], correct:1, explanation:"Out-of-scope testing can be unauthorized access with legal exposure; documenting it does not make it legal." },
  { id:90179, domain:1, level:1, question:"What is the difference between a red team engagement and a standard penetration test?", options:["A red team never uses any real attack techniques, whereas a standard penetration test always uses live exploits","A red team is only ever performed by internal staff, whereas a penetration test must always be fully external overall","A red team emphasizes stealthy, objective-driven adversary emulation, while a pen test emphasizes broad coverage","A red team focuses purely on documentation review, whereas a penetration test focuses only on physical access"], correct:2, explanation:"Red teaming is stealthy and goal-driven; pen tests aim for broad coverage of findings." },
  { id:90180, domain:1, level:2, question:"What does 'scope creep' refer to in a penetration test?", options:["The natural improvement of the tester's skills over the course of a single long-running engagement period here","The process of formally reducing the agreed scope after mutual written approval from both of the parties later","The automatic escalation of user privileges to administrator during the post-exploitation phase of the work now","The gradual, uncontrolled expansion of engagement boundaries beyond what was originally agreed with the client"], correct:3, explanation:"Scope creep is uncontrolled expansion of boundaries; controlled reduction with approval is not creep." },
  { id:90181, domain:1, level:3, question:"Which of the following is a passive information-gathering technique?", options:["Reviewing a target company's public job postings to infer the technologies and platforms they currently use here","Running a full TCP connect scan against the target's public web servers to enumerate all of their open ports","Sending crafted HTTP requests to the target application in order to fingerprint its underlying web framework","Performing a DNS zone transfer attempt directly against the target's authoritative name servers on the wire overall"], correct:0, explanation:"Reading public job postings is passive; scanning and zone transfers are active." },
  { id:90182, domain:1, level:2, question:"What is a primary benefit of maintaining detailed notes during an engagement?", options:["They automatically exploit any vulnerabilities that the tester happens to record within the notes themselves","They support accurate reporting and provide an auditable record of exactly what actions the tester performed","They eliminate the need to obtain any client authorization because the notes serve as a legal substitute for it","They guarantee that the tester will never trigger any security alerts on the systems being actively assessed"], correct:1, explanation:"Notes enable accurate reporting and an audit trail; they do not exploit or authorize anything." },
  { id:90183, domain:1, level:3, question:"What is the purpose of a 'de-confliction' contact during a red team engagement?", options:["A tool that automatically resolves conflicts between two different exploits attempting to run on one host at once","A legal clause that removes the requirement to define any scope before the engagement is allowed to begin work","A trusted client contact who can confirm whether suspicious activity is the red team or a genuine real attacker","A scanner setting that prevents the red team from ever generating any log entries on the target systems at all"], correct:2, explanation:"De-confliction is a trusted contact to distinguish the team from real attackers, not a tool or clause." },
  { id:90184, domain:1, level:2, question:"Which Nmap timing template is the slowest and stealthiest?", options:["The -T5 (insane) template, which is actually the fastest and noisiest option rather than the stealthiest one","The -T3 (normal) template, which is the default balanced timing and is neither the slowest nor the fastest one","The -A option, which enables aggressive feature detection and is not a timing template controlling scan speed","The -T0 (paranoid) template, which is the slowest option and is intended to help evade detection systems here"], correct:3, explanation:"-T0 is the slowest and stealthiest; -T5 is the fastest and noisiest." },
  { id:90185, domain:1, level:1, question:"What does an Nmap 'filtered' port state usually indicate?", options:["That a firewall or filter is blocking probes, so Nmap cannot determine whether the port is open or closed here","That the port is definitely open and actively accepting connections from any client on the network segment overall","That the port is definitely closed and is actively sending TCP reset packets back to the scanning host now","That the target host is completely offline and is not responding to any packets at all during the entire scan"], correct:0, explanation:"'Filtered' means a firewall blocks probes; 'open' and 'closed' are distinct definitive states." },
  { id:90186, domain:1, level:2, question:"Which scan type completes the full three-way TCP handshake?", options:["The TCP SYN scan (-sS), which only sends a SYN and then tears down before completing the full handshake now","The TCP connect scan (-sT), which completes the full three-way handshake with each of the target's open ports","The UDP scan (-sU), which uses connectionless UDP datagrams and therefore has no TCP handshake to complete overall","The idle scan (-sI), which uses a zombie host and never completes a direct handshake from the scanner itself"], correct:1, explanation:"-sT completes the full handshake; -sS is half-open and does not." },
  { id:90187, domain:1, level:3, question:"What is the main advantage of a SYN scan over a full connect scan?", options:["It is the only scan type that is capable of detecting the operating system version running on the target host","It guarantees that the scan will never once be detected by any modern intrusion detection system whatsoever","It is faster and stealthier because it never completes the handshake, often avoiding application-level logging","It automatically exploits each open port that it discovers rather than merely reporting the port as being open"], correct:2, explanation:"SYN scans are faster and often avoid app logs; they do not guarantee stealth or exploit ports." },
  { id:90188, domain:1, level:2, question:"Which protocol is commonly enumerated to reveal Windows shares and user accounts?", options:["ICMP, which is used mainly for reachability testing and does not expose Windows shares or user accounts at all","NTP, which synchronizes system clocks and does not enumerate any Windows shares or account information itself","TFTP, which transfers files without authentication and does not reveal Windows share or user account details","SMB, which can be enumerated to reveal Windows network shares, user accounts, and other host information here"], correct:3, explanation:"SMB enumeration reveals shares and accounts; ICMP only tests reachability." },
  { id:90189, domain:1, level:3, question:"SNMP enumeration with a default community string can reveal what?", options:["Detailed device configuration and system information, especially when the default 'public' community is in use","The plaintext contents of every encrypted TLS session that the device has ever established with any client","The private RSA keys that protect the device's SSH server, which SNMP is specifically designed to disclose","Nothing at all, because SNMP never exposes any device information regardless of the community string used for the target"], correct:0, explanation:"Default SNMP community strings can leak config and system info; SNMP does not expose TLS session contents." },
  { id:90190, domain:1, level:2, question:"What information can a DNS zone transfer potentially reveal to a tester?", options:["The plaintext passwords for every user account that exists within the organization's Active Directory domain","A full list of an organization's DNS records, exposing internal hostnames and the structure of its network","The complete source code of the organization's public-facing web applications hosted on its own web servers","A real-time feed of the organization's live network traffic as it traverses the perimeter routers currently"], correct:1, explanation:"A zone transfer can expose all DNS records and internal hostnames; it does not reveal passwords or source code." },
  { id:90191, domain:1, level:1, question:"Why is LDAP enumeration valuable to a penetration tester?", options:["It automatically cracks every domain password because LDAP stores all credentials entirely in plaintext form","It disables the target's firewall so that all subsequent scans will complete without any filtering occurring","It can reveal directory information such as users, groups, and organizational structure within the environment","It installs a persistent backdoor on the domain controller as a normal side effect of any LDAP query at all overall"], correct:2, explanation:"LDAP enumeration reveals directory info like users and groups; it does not crack passwords or install backdoors." },
  { id:90192, domain:1, level:2, question:"Which law in the United States broadly criminalizes unauthorized access to computer systems?", options:["The Health Insurance Portability and Accountability Act, which instead governs the privacy of health records overall","The Sarbanes-Oxley Act, which primarily governs corporate financial reporting and related accounting controls","The Digital Millennium Copyright Act, which chiefly addresses copyright and the circumvention of DRM measures","The Computer Fraud and Abuse Act, which broadly criminalizes unauthorized access to protected computer systems"], correct:3, explanation:"The CFAA criminalizes unauthorized access; HIPAA governs health data privacy instead." },
  { id:90193, domain:1, level:3, question:"Which regulation specifically requires periodic penetration testing of cardholder data environments?", options:["PCI DSS, which requires organizations that handle cardholder data to perform periodic penetration testing work","GDPR, which governs the protection of the personal data of individuals but does not mandate periodic pen tests","HIPAA, which governs the privacy of protected health information rather than any card payment environments here","SOX, which governs the accuracy of corporate financial reporting rather than cardholder data testing schedules"], correct:0, explanation:"PCI DSS mandates periodic pen testing of cardholder environments; GDPR is a data-protection regulation." },
  { id:90194, domain:1, level:2, question:"What is the safest way to handle sensitive data captured during a penetration test?", options:["Post it to a shared public repository so the client can conveniently download all of the captured data anytime","Store it encrypted, limit access, and securely destroy it after the engagement per the agreed data-handling terms","Keep unencrypted copies indefinitely on the tester's personal laptop for potential use in future engagements","Email the full raw dataset to every stakeholder involved so that nobody is ever left out of the loop at all overall"], correct:1, explanation:"Sensitive data must be encrypted, access-limited, and securely destroyed; public posting is unacceptable." },
  { id:90195, domain:1, level:3, question:"Which tool is primarily used to brute-force online login services over the network?", options:["Wireshark, which is a passive packet capture tool and does not perform online credential brute-forcing at all","Nikto, which is a web server scanner and is not primarily an online authentication brute-forcing utility here","Hydra, which is a fast tool used to brute-force many online authentication services across various protocols","Nmap, which performs port scanning and service detection rather than brute-forcing any online login services"], correct:2, explanation:"Hydra brute-forces online logins; Wireshark only captures packets." },
  { id:90196, domain:1, level:2, question:"Which tool is a web server scanner that checks for dangerous files and outdated software?", options:["Aircrack-ng, which is a wireless security assessment suite rather than a web server vulnerability scanner tool","John the Ripper, which is an offline password hash cracker and does not scan any web servers for known issues","Netcat, which is a general-purpose networking utility and is not a dedicated web server vulnerability scanner","Nikto, which is an open-source web server scanner that checks for dangerous files and outdated server software"], correct:3, explanation:"Nikto scans web servers for known issues; Aircrack-ng targets wireless networks." },
  { id:90197, domain:1, level:1, question:"What is Netcat commonly described as in penetration testing?", options:["A versatile networking utility often called the 'Swiss Army knife' for reading and writing network connections","A graphical vulnerability scanner that automatically produces a full risk-rated report of all discovered flaws","A dedicated wireless cracking suite that is used exclusively to recover WPA2 pre-shared keys from captures","A commercial SIEM platform that correlates security events collected from across an entire enterprise network"], correct:0, explanation:"Netcat is a flexible networking 'Swiss Army knife'; it is not a scanner or SIEM." },
  { id:90198, domain:1, level:2, question:"Within Metasploit, what is the purpose of an auxiliary module?", options:["To always deliver a Meterpreter payload, since every auxiliary module is by definition a full remote exploit","To perform supporting tasks such as scanning, fuzzing, or enumeration that do not deliver an exploit payload","To generate the final client report automatically once all of the exploitation activities have been completed","To serve as the legal authorization document that permits the tester to attack the target during the engagement"], correct:1, explanation:"Auxiliary modules do scanning and enumeration without delivering an exploit payload." },
  { id:90199, domain:1, level:3, question:"What is Meterpreter in the context of Metasploit?", options:["A network port scanner that runs before exploitation to enumerate every open service on the target host first overall","A static analysis engine that reviews application source code for security flaws prior to any runtime testing","An advanced in-memory payload that provides an interactive shell with many post-exploitation capabilities built in","A reporting module that compiles the executive summary section of the final deliverable for the client to read"], correct:2, explanation:"Meterpreter is an in-memory post-exploitation payload; it is not a scanner or reporting module." },
  { id:90200, domain:1, level:2, question:"What is the primary purpose of the reconnaissance phase?", options:["To immediately gain administrative access to the target's most critical servers before doing anything else at all","To write and deliver the final executive report to the client before any technical activity has actually begun","To permanently remove the target's vulnerabilities as they are discovered during the information-gathering step","To gather as much information as possible about the target to inform later scanning and exploitation activities"], correct:3, explanation:"Recon gathers information to guide later phases; it does not exploit or remediate anything." },
  { id:90201, domain:1, level:3, question:"Which of the following best defines a 'false positive' in vulnerability scanning?", options:["A reported vulnerability that does not actually exist or is not exploitable in the environment being assessed","A genuine vulnerability that the scanner correctly identified and that a tester later confirmed to be exploitable","A vulnerability that the scanner completely missed even though it was present and exploitable on the target host","A network port that the scanner correctly reported as open and that was later confirmed to be genuinely open"], correct:0, explanation:"A false positive is a reported issue that is not real; a missed real issue is a false negative instead." },
  { id:90202, domain:1, level:2, question:"Which of the following best defines a 'false negative' in vulnerability scanning?", options:["A vulnerability that the scanner reported but that does not actually exist within the assessed environment here","A real, exploitable vulnerability that the scanner failed to detect during the assessment of the environment","A finding that the scanner correctly reported and that was subsequently confirmed as a genuine exploitable flaw","A closed network port that the scanner accurately reported as being closed during the completed scanning run"], correct:1, explanation:"A false negative is a missed real vulnerability; a non-existent reported issue is a false positive." },
  { id:90203, domain:1, level:1, question:"Why should a tester obtain emergency contact information before starting?", options:["So that the tester can freely share the client's internal contact list with unrelated third parties afterward","So that the requirement for any written authorization can be conveniently bypassed during the engagement work","So that critical issues or accidental outages can be escalated to the right client personnel without any delay","So that the tester is able to bill the client for extra hours whenever an emergency contact is used at all now"], correct:2, explanation:"Emergency contacts enable rapid escalation of critical issues or outages; they do not bypass authorization." },
  { id:90204, domain:1, level:2, question:"What is the main purpose of a debrief meeting after an engagement?", options:["To renegotiate the entire contract price after the technical testing work has already been fully completed now","To publicly disclose the client's vulnerabilities to the media before the client has a chance to remediate them","To transfer legal ownership of every discovered vulnerability from the client over to the testing organization","To walk the client through the findings, answer questions, and align on remediation priorities and next steps"], correct:3, explanation:"A debrief reviews findings and remediation priorities; it is not for public disclosure or renegotiation." },
  { id:90205, domain:1, level:3, question:"What does 'pivoting' refer to during post-exploitation?", options:["Using a compromised host as a relay to reach and attack additional systems on networks otherwise not reachable","Rewriting the final report from a technical format into an executive format for the client's leadership readers","Switching from one vulnerability scanner to a different one midway through the assessment for better coverage","Rotating the tester's public IP address repeatedly in order to evade the target's basic rate-limiting controls"], correct:0, explanation:"Pivoting uses a compromised host to reach otherwise-unreachable networks; it is not report formatting." },
  { id:90206, domain:1, level:2, question:"What is the primary purpose of privilege escalation after gaining initial access?", options:["To immediately write the final report, since higher privileges are required before any report may be produced overall","To obtain higher-level permissions, such as administrator or root, expanding control over the compromised system","To reduce the tester's access down to a guest level so as to minimize any potential impact on the environment","To notify the target's defenders that the tester now has access so they can respond to the intrusion promptly"], correct:1, explanation:"Privilege escalation gains higher permissions like root or admin; it does not reduce access or notify defenders." },
  { id:90207, domain:1, level:3, question:"What is a key ethical reason to avoid causing denial of service during testing unless explicitly authorized?", options:["Because denial of service is the single most effective way to accurately measure a system's real security posture","Because causing an outage automatically ends the tester's legal liability for anything that occurs afterward now","Because unplanned outages can harm the client's business and typically fall outside the agreed rules of engagement","Because clients always expect and appreciate unannounced outages as convincing proof of a thorough assessment overall"], correct:2, explanation:"Unauthorized DoS can harm the business and breach the RoE; it is not a routine or welcomed technique." },
  { id:90208, domain:1, level:2, question:"Which activity best represents the 'information gathering' phase of PTES?", options:["Delivering the polished final report along with all remediation guidance to the client's executive leadership","Signing the statement of work and the non-disclosure agreement between the tester and the client organization","Cleaning up any artifacts and removing all tester-created accounts from the systems at the end of the test","Collecting OSINT and technical data about the target to build a comprehensive picture before deeper testing"], correct:3, explanation:"Information gathering collects OSINT and technical data; SOW signing is pre-engagement." },
  { id:90209, domain:1, level:1, question:"What is the benefit of using a standardized methodology like PTES or NIST SP 800-115?", options:["It provides a repeatable, comprehensive structure that improves consistency and thoroughness across engagements","It legally authorizes the tester to attack any system, removing the need for a signed permission document at all","It guarantees that no vulnerabilities will ever be missed on any target regardless of the environment complexity","It automatically generates a complete, client-ready final report without any input required from the tester now"], correct:0, explanation:"Standard methodologies add repeatability and thoroughness; they do not authorize or auto-report." },
  { id:90210, domain:1, level:2, question:"What is 'attack surface' in the context of penetration testing?", options:["The single most critical vulnerability that exists on the target, chosen from among all discovered weaknesses","The sum of all points where an attacker could attempt to enter, interact with, or extract data from a system","The physical floor space occupied by the servers and networking equipment inside the organization's facility","The total amount of money that an organization has budgeted for its security testing efforts in a given year"], correct:1, explanation:"Attack surface is the set of possible entry and interaction points; it is not a single vuln or a budget." },
  { id:90211, domain:1, level:3, question:"Why is it important to define 'success criteria' or objectives before an engagement?", options:["So the tester can freely change the objectives at any time without ever informing the client organization at all","So that the requirement to obtain written authorization for the testing can be conveniently avoided entirely","So both parties agree on what the test should achieve, focusing effort and enabling clear evaluation afterward","So the client is contractually prevented from ever reviewing or questioning any of the tester's later findings"], correct:2, explanation:"Defined objectives focus effort and enable evaluation; they do not remove authorization needs." },
  { id:90212, domain:1, level:2, question:"What is the recommended approach when a test unexpectedly causes a production outage?", options:["Continue testing silently and hope the affected system recovers on its own before anyone at the client notices","Delete all of the logs relating to the outage so that the client is never able to trace it back to the testing","Blame the outage on an unrelated real attacker in the final report to avoid any responsibility for the incident","Immediately notify the client's emergency contact, pause testing, and assist with recovery per the agreed plan"], correct:3, explanation:"Outages require immediate notification and assistance, not concealment or blame-shifting." },
  { id:90213, domain:1, level:3, question:"Which phase involves removing tester-created artifacts and restoring systems to their prior state?", options:["The cleanup phase, in which the tester removes created accounts, tools, and artifacts to restore the environment","The pre-engagement phase, in which the scope and the rules of engagement are first agreed with the client team","The reconnaissance phase, in which passive and active information gathering about the target is first performed","The scanning phase, in which the tester enumerates the open ports and running services present on the targets overall"], correct:0, explanation:"Cleanup removes tester artifacts and restores systems; recon and scanning are earlier phases." },
  { id:90214, domain:1, level:2, question:"What is the primary purpose of a CVSS score in reporting?", options:["To legally authorize the exploitation of the vulnerability that the score has been calculated and assigned for","To provide a standardized numeric severity rating that helps consistently communicate and compare vulnerability risk","To guarantee that the vulnerability will be fully patched by the vendor within a fixed and predefined timeframe","To automatically remediate the vulnerability on the affected system as soon as the score has been calculated overall"], correct:1, explanation:"CVSS gives a standardized severity rating for communication; it does not authorize, patch, or guarantee fixes." },
  { id:90215, domain:1, level:1, question:"How does a gray box test typically improve efficiency over a pure black box test?", options:["It removes any need to obtain written authorization, since partial knowledge already implies client consent given","It guarantees complete coverage of every possible vulnerability that could ever exist within the whole environment","Partial knowledge lets the tester focus effort on likely weak points rather than rediscovering the basics slowly","It eliminates the reporting phase entirely because the client already knows the internal details being provided"], correct:2, explanation:"Partial knowledge focuses effort efficiently; it does not remove authorization or reporting needs." },
  { id:90216, domain:1, level:2, question:"What best describes 'adversary emulation'?", options:["Running a fully automated vulnerability scanner and then exporting its raw output directly as the final report","Reviewing only the written security policies of an organization without ever testing any of its live systems overall","Physically inspecting the server room for unauthorized devices while ignoring any of the network-based threats","Replicating the tactics and techniques of a specific, known threat actor to test defenses against realistic attacks"], correct:3, explanation:"Adversary emulation replicates a known actor's TTPs; it is more than an automated scan or policy review." },
  { id:90217, domain:1, level:3, question:"Why should testers verify scanner findings manually where possible?", options:["Because manual verification confirms real exploitability and filters out false positives before they reach clients","Because manual verification is legally required to occur before the scanner may even be run against the target","Because scanners are never able to detect any vulnerabilities at all without direct manual assistance from a tester","Because manual verification automatically patches each confirmed vulnerability immediately after it is validated"], correct:0, explanation:"Manual verification confirms exploitability and removes false positives; it does not patch anything." },
  { id:90218, domain:1, level:2, question:"What is the main goal of the exploitation phase?", options:["To merely list the vulnerabilities without ever attempting to confirm whether any of them are truly exploitable","To confirm and demonstrate that identified vulnerabilities can be leveraged to gain access or otherwise cause impact","To obtain the initial signed authorization from the client that is required before any testing can take place overall","To draft the executive summary of the final report for the client's non-technical leadership audience to read"], correct:1, explanation:"Exploitation confirms and demonstrates real impact; merely listing issues is a vulnerability assessment." },
  { id:90219, domain:1, level:3, question:"What is the value of mapping findings to a framework like MITRE ATT&CK in a report?", options:["It legally transfers responsibility for the vulnerabilities from the client organization onto the testing party","It guarantees that the client's security team will detect every future attack without any additional tooling overall","It helps defenders understand which real-world techniques were used and prioritize corresponding detective controls","It replaces the entire remediation section because framework references alone tell the client exactly what to fix"], correct:2, explanation:"ATT&CK mapping helps defenders prioritize detections; it does not transfer liability or replace remediation." },
  { id:90220, domain:1, level:2, question:"What is the purpose of banner grabbing during enumeration?", options:["To immediately crash the service being examined so that its downtime can be measured precisely during the test","To obtain the client's written authorization for the engagement before any of the active testing has started","To permanently patch the identified service so that it can no longer be exploited by any future attacker at all","To identify the software name and version of a running service so known vulnerabilities can be researched later"], correct:3, explanation:"Banner grabbing identifies service and version for vuln research; it does not crash or patch services." },
  { id:90221, domain:1, level:1, question:"Why is stakeholder communication important throughout an engagement?", options:["It keeps the client informed of progress and critical issues, building trust and enabling timely decisions to be made","It allows the tester to skip the reporting phase entirely because verbal updates fully replace any written report","It transfers all of the tester's legal responsibilities directly onto the various stakeholders being communicated to","It ensures the tester can expand the scope at will since regular communication implies unlimited client consent overall"], correct:0, explanation:"Communication builds trust and enables timely decisions; it does not replace reporting or expand scope." },
  { id:90222, domain:1, level:2, question:"What distinguishes a 'technique' from a 'tactic' in MITRE ATT&CK?", options:["A tactic is always automated software, while a technique is always a manual action performed by a human operator","A tactic is the adversary's goal, while a technique is the specific method used to achieve that particular goal","A tactic applies only to web applications, while a technique applies only to internal Active Directory networks","A tactic is a legal document, while a technique is the invoice submitted to the client at the end of the test"], correct:1, explanation:"Tactics are goals; techniques are the how. Neither is a legal document or restricted to one platform." },
  { id:90223, domain:1, level:3, question:"What is the benefit of using a repeatable checklist during enumeration?", options:["It legally authorizes the tester to attack the target, removing the need for any signed permission document at all","It guarantees that the enumeration phase will never generate any log entries on any of the systems assessed here","It reduces the chance of overlooking important hosts or services and improves consistency across engagements today","It automatically writes the final report so the tester does not need to document any findings themselves at all"], correct:2, explanation:"A checklist improves consistency and coverage; it does not authorize or auto-report." },
  { id:90224, domain:1, level:2, question:"Why should a tester understand the client's business context before testing?", options:["So the tester can bypass the requirement for written authorization by claiming familiarity with the business now","So the tester can guarantee that absolutely no vulnerabilities will be found within the client's environment ever","So the tester can charge a substantially higher fee simply for having read the client's public marketing pages","So findings can be prioritized by real business impact rather than by raw technical severity scores in isolation"], correct:3, explanation:"Business context enables impact-based prioritization; it does not bypass authorization." },
  { id:90225, domain:1, level:3, question:"What is the recommended handling of credentials discovered during a test?", options:["Record them securely, use them only within scope, and include appropriate handling and disposal in the reporting","Publish them to a public paste site so that the client can retrieve any credentials that they happen to need later","Reuse them freely against any external third-party systems that the tester encounters during the engagement work","Keep permanent personal copies indefinitely for potential use during unrelated future client engagements later on"], correct:0, explanation:"Discovered credentials must be handled securely and used only in scope; public posting or reuse is improper." },
  { id:90226, domain:1, level:2, question:"What is the main reason to test during an agreed maintenance window when possible?", options:["To ensure that the client's security monitoring team is fully asleep and therefore unable to detect the testing","To minimize the impact of any disruptive testing on the client's normal business operations and their end users","To remove the requirement to obtain any written authorization because off-hours testing is always permitted here","To guarantee that the tester will discover far more vulnerabilities than would be found during normal work hours"], correct:1, explanation:"Maintenance windows reduce operational impact; they do not remove authorization or improve findings counts." },
  { id:90227, domain:1, level:1, question:"What is the purpose of retesting after remediation?", options:["To discover an entirely new and unrelated set of vulnerabilities that were never part of the original scope here","To renegotiate the original contract price upward now that the client has already seen the initial set of findings","To confirm that the previously reported vulnerabilities have actually been fixed and no longer remain exploitable","To transfer full ownership of any remaining vulnerabilities from the client over to the testing organization now"], correct:2, explanation:"Retesting confirms fixes are effective; it is not for scope expansion or renegotiation." },
  { id:90228, domain:1, level:2, question:"Why is it important to document the exact tools and versions used during a test?", options:["To legally authorize the use of those specific tools, removing the need for any signed permission from the client","To guarantee that the same tools will detect every possible vulnerability in any future engagement automatically","To transfer responsibility for any tool-caused outages entirely onto the vendors that produced those same tools","To make the engagement reproducible and to help the client understand and validate how each finding was produced"], correct:3, explanation:"Documenting tools and versions aids reproducibility and validation; it does not authorize or transfer liability." },
  { id:90229, domain:1, level:3, question:"What best describes the goal of 'defense evasion' as an ATT&CK tactic?", options:["Avoiding detection by security controls, for example by disabling logging or obscuring malicious activity on a host","Publicly announcing every action to the defenders so that they can respond to the intrusion as quickly as possible","Formally authorizing the engagement in writing before any of the testing activities are permitted to take place","Producing the final client-facing report at the conclusion of the engagement for the leadership team to review overall"], correct:0, explanation:"Defense evasion is about avoiding detection; it is neither announcing activity nor reporting." },
  { id:90230, domain:1, level:2, question:"What is the primary purpose of the OWASP Top 10?", options:["To provide a complete legal contract template for authorizing all web application penetration testing work","To raise awareness of the most critical web application security risks so teams can prioritize their defenses","To list every known vulnerability that has ever existed in any web application across the entire industry","To rank commercial web application firewalls by price so buyers can choose the cheapest option available in this context"], correct:1, explanation:"OWASP Top 10 raises awareness of top web risks; it is not a contract or exhaustive vuln list." },
  { id:90231, domain:1, level:3, question:"Which is a characteristic of a double-blind penetration test?", options:["Both the testers and the defenders receive complete information about every step planned in the engagement","Only the testers are given full internal knowledge while the defenders are fully briefed on the timeline","Neither the testers nor the organization's defenders are informed of the schedule or details in advance","The engagement is limited strictly to reviewing documentation and never touches any live production system"], correct:2, explanation:"Double-blind means defenders are unaware; a fully briefed test is not double-blind." },
  { id:90232, domain:1, level:2, question:"What is 'social engineering' in the context of penetration testing?", options:["Rewiring the physical network cabling of an office in order to intercept traffic between the workstations for the target","Automatically scanning every open port on a target host to enumerate the services that are listening there","Cracking captured password hashes offline using a large wordlist and a high-performance graphics processor","Manipulating people into divulging information or performing actions that compromise security of the target"], correct:3, explanation:"Social engineering manipulates people; scanning and cracking are technical, not human-focused." },
  { id:90233, domain:1, level:1, question:"Which technique is an example of active OS fingerprinting?", options:["Sending crafted packets to a host and analyzing the responses to infer the operating system it is running","Reading the organization's public press releases to guess which server platforms they might have purchased","Reviewing archived versions of the company website to estimate the age of its underlying infrastructure","Searching a public certificate transparency log for subdomains that belong to the target organization only"], correct:0, explanation:"Active OS fingerprinting probes the host directly; reading press releases is passive." },
  { id:90234, domain:1, level:2, question:"What is the purpose of the 'scoping' document in an engagement?", options:["To provide the client with a detailed list of exploits that will be guaranteed to succeed on their systems","To define precisely which systems, networks, and activities are and are not included in the assessment work","To transfer all legal liability for any and every possible outcome directly onto the client organization in this context","To replace the requirement for a written report by documenting the findings entirely within the scope file"], correct:1, explanation:"Scoping defines what is in and out of scope; it does not guarantee exploits or replace the report." },
  { id:90235, domain:1, level:3, question:"What does a 'zombie' host refer to in an Nmap idle scan?", options:["The tester's own laptop, which is configured to send every scan packet directly from its own address here","A host that has already been fully compromised and now hosts the tester's command-and-control channel only","An idle third-party host whose predictable IP ID sequence is used to scan a target without direct contact","A decommissioned server that has been powered off and therefore cannot participate in any scan whatsoever"], correct:2, explanation:"The idle scan uses an idle third-party host's IP ID; it is not the tester's own machine." },
  { id:90236, domain:1, level:2, question:"Why might a tester use a UDP scan in addition to a TCP scan?", options:["Because UDP scanning is the only reliable method available for detecting the operating system of a target","Because UDP scans always complete far faster and more reliably than any equivalent TCP-based scan would","Because UDP scanning automatically exploits every service that it discovers rather than merely listing them","Because important services such as DNS, SNMP, and DHCP run over UDP and would be missed by a TCP-only scan"], correct:3, explanation:"Key services run over UDP; a TCP-only scan misses them. UDP scans are actually slower and less reliable." },
  { id:90237, domain:1, level:3, question:"What is the primary goal of the 'weaponization' concept in an attack lifecycle?", options:["Coupling an exploit with a payload into a deliverable form that can be used against the chosen target host","Publicly disclosing a vulnerability to the affected vendor so that a patch can be developed and released","Writing the final client report that summarizes all of the findings for the leadership team to review later","Physically securing the tester's laptop so that it cannot be stolen while traveling to the client's office"], correct:0, explanation:"Weaponization couples an exploit with a payload into a deliverable; it is not disclosure or reporting." },
  { id:90238, domain:1, level:2, question:"What is a 'reverse shell'?", options:["A connection the attacker opens directly into the target that the firewall always permits without any rules","A connection initiated from a compromised target back to the attacker, giving the attacker command access","A tool that reverses the order of characters in captured passwords to make them easier to crack offline","A backup process that restores a compromised system to its original state after the engagement concludes"], correct:1, explanation:"A reverse shell has the target connect back to the attacker, often bypassing inbound firewall rules." },
  { id:90239, domain:1, level:1, question:"What is the difference between a 'bind shell' and a 'reverse shell'?", options:["A bind shell always uses encryption, while a reverse shell is always sent entirely in unencrypted plaintext","A bind shell works only on Windows hosts, while a reverse shell works only on Linux hosts in every scenario","A bind shell listens on the target for the attacker to connect, while a reverse shell connects out to attacker","A bind shell is a reporting artifact, while a reverse shell is a legal document authorizing the engagement overall"], correct:2, explanation:"A bind shell listens on the target; a reverse shell dials back to the attacker." },
  { id:90240, domain:1, level:2, question:"Why is maintaining an audit log of tester actions important?", options:["It legally authorizes the engagement, so no separate signed permission document is required from the client","It guarantees that the tester's activity will never once be detected by the client's monitoring systems now","It automatically remediates every vulnerability that is recorded within the log as the test proceeds along overall","It provides accountability and lets the client correlate any observed anomalies with authorized test activity"], correct:3, explanation:"Audit logs give accountability and enable correlation; they do not authorize or remediate anything." },
  { id:90241, domain:1, level:3, question:"What best describes 'persistence' as a post-exploitation objective?", options:["Establishing a reliable way to retain access to a compromised system even after reboots or credential changes","Repeatedly rescanning the same host until every single one of its open ports has finally been fully mapped","Persuading the client to extend the engagement contract so that additional testing days can be added later","Writing detailed and persistent notes about the engagement so the final report is as thorough as possible for the target"], correct:0, explanation:"Persistence means retaining access across reboots; it is not rescanning or note-taking." },
  { id:90242, domain:1, level:2, question:"What is the purpose of 'password spraying' as an attack technique?", options:["Trying thousands of passwords against a single account as quickly as possible regardless of any lockout policy","Trying a few common passwords across many accounts to avoid the lockouts that per-account brute forcing causes","Capturing packets on the network in order to passively read passwords that are transmitted in plaintext form","Generating a completely random new password for each user account to improve the organization's security"], correct:1, explanation:"Password spraying uses a few passwords across many accounts to evade lockouts; brute force hammers one account." },
  { id:90243, domain:1, level:3, question:"What is the main reason penetration testers use virtual machines and isolated lab environments?", options:["To permanently store all of the client's sensitive data in an unencrypted form for convenient later access","To remove the requirement for written authorization because lab work is exempt from all legal restrictions","To safely practice and test tools and exploits without risking damage to production or third-party systems","To guarantee that any exploit tested in the lab will always succeed identically against the real target host"], correct:2, explanation:"Labs let testers practice safely without harming production; lab success does not guarantee real success." },
  { id:90244, domain:1, level:2, question:"What is 'enumeration' of a web application most likely to reveal?", options:["The plaintext database administrator password, which web enumeration always reliably discloses every time","The physical location of the data center where the web application's servers are housed and maintained","A signed legal contract that authorizes the tester to perform the assessment against the web application","Directories, endpoints, technologies, and input points that expand the tester's understanding of the app"], correct:3, explanation:"Web enumeration reveals endpoints, tech, and inputs; it does not disclose the DB admin password by itself." },
  { id:90245, domain:1, level:1, question:"Which of the following is a legitimate reason to pause a penetration test immediately?", options:["The tester discovers signs of an active, unrelated real-world compromise on the client's target systems","The tester finds a low-severity informational issue that has no meaningful impact on the client at all","The tester wants to take an unscheduled break without informing the client or their emergency contact","The tester decides the client's environment is too well secured to be worth continuing the assessment on"], correct:0, explanation:"An active real compromise warrants an immediate pause and notification; a minor info finding does not." },
  { id:90246, domain:1, level:2, question:"What is the value of a 'proof of concept' in a penetration test finding?", options:["It legally authorizes the exploitation of the vulnerability without any separate permission from the client","It demonstrates that a vulnerability is genuinely exploitable, helping the client grasp the real-world impact","It guarantees that the vulnerability can never be reintroduced into the environment at any point in future","It replaces the executive summary entirely because a technical demonstration is all leadership ever needs for the target"], correct:1, explanation:"A proof of concept shows real exploitability and impact; it does not authorize or replace the summary." },
  { id:90247, domain:1, level:3, question:"Why should testers avoid using production credentials found during testing beyond the agreed scope?", options:["Because production credentials always expire the instant they are discovered and therefore cannot be reused overall","Because the client is legally required to change all passwords the moment any credential is ever discovered","Because using them outside scope may constitute unauthorized access and breach the agreed rules of engagement","Because found credentials are automatically encrypted and can never actually be used against any real system"], correct:2, explanation:"Using found credentials out of scope can be unauthorized access breaching the RoE." },
  { id:90248, domain:1, level:2, question:"What is the purpose of segmentation testing in a PCI DSS context?", options:["To confirm that every employee has memorized the organization's full information security policy document","To measure the raw processing speed of the payment application under a heavy simulated transaction load in this context","To automatically encrypt all stored cardholder data using a key generated during the testing engagement","To verify that the cardholder data environment is properly isolated from the rest of the corporate network"], correct:3, explanation:"Segmentation testing verifies isolation of the cardholder data environment; it is not a performance test." },
  { id:90249, domain:1, level:3, question:"What is a key characteristic of a 'white box' code review during testing?", options:["The reviewer has full access to source code, allowing deep analysis of logic and hard-to-reach vulnerabilities","The reviewer has no access to the source and must infer everything purely from the running application only","The reviewer is limited to reading the application's public marketing materials and nothing more than that","The reviewer may only run automated scanners and is never permitted to read any of the source code lines in this context"], correct:0, explanation:"White box review has full source access for deep analysis; black box has none." },
  { id:90250, domain:1, level:2, question:"Why is it important to obtain sign-off on the final report from the client?", options:["It legally transfers ownership of every discovered vulnerability from the client onto the testing company now","It confirms the client has received and acknowledged the findings, formally closing out the engagement work","It guarantees the client will remediate every finding within a strict and legally binding fixed timeframe","It removes the requirement for the tester to have obtained any written authorization before starting work"], correct:1, explanation:"Sign-off confirms receipt and closes the engagement; it does not transfer liability or force remediation." },
  { id:90251, domain:1, level:1, question:"What does 'CVE' stand for in vulnerability management?", options:["Critical Vulnerability Evaluation, an internal scoring method used only by a single commercial scanner vendor","Certified Vulnerability Examiner, a professional certification for individuals who perform security testing","Common Vulnerabilities and Exposures, a standardized identifier system for publicly known security flaws today","Continuous Verification Engine, an automated tool that constantly re-scans systems for configuration drift overall"], correct:2, explanation:"CVE is Common Vulnerabilities and Exposures, a standard identifier system for known flaws." },
  { id:90252, domain:1, level:2, question:"How does CVSS differ from CVE?", options:["CVSS is a legal contract template, while CVE is the invoice submitted to the client after the engagement ends","CVSS and CVE are identical terms that both refer to the same standardized vulnerability naming scheme exactly","CVSS is a wireless cracking tool, while CVE is a web application intercepting proxy used during the testing overall","CVSS is a scoring system for severity, while CVE is an identifier that uniquely names a specific vulnerability"], correct:3, explanation:"CVSS scores severity; CVE names the vulnerability. They are complementary, not identical." },
  { id:90253, domain:1, level:3, question:"What is the primary risk of relying solely on automated vulnerability scanners?", options:["They can produce false positives and negatives and miss business-logic flaws that require human analysis","They are unable to detect any open network ports whatsoever and therefore provide no useful information","They automatically exploit every host they touch, causing widespread outages across the entire environment","They legally invalidate the engagement authorization the moment they are executed against any live system"], correct:0, explanation:"Scanners produce false results and miss logic flaws; human analysis is still needed." },
  { id:90254, domain:1, level:2, question:"What is 'lateral movement' in a network penetration test?", options:["Upgrading a normal user account to an administrator account on the very same single host already compromised","Moving from one compromised host to other systems within the network to expand access toward the objective","Rewriting the final report so that its technical findings are understandable to a non-technical audience here","Physically relocating the tester's equipment from one office building to another during the engagement work"], correct:1, explanation:"Lateral movement spreads across hosts; escalating on the same host is privilege escalation." },
  { id:90255, domain:1, level:3, question:"Why should the rules of engagement specify testing hours and blackout periods?", options:["To guarantee that the tester will discover the maximum possible number of vulnerabilities on every system","To remove the need for any written authorization because timing rules already imply full client consent","To ensure disruptive testing does not occur during critical business windows the client wants to protect","To transfer legal responsibility for any outages entirely onto whichever tester happens to be on shift then"], correct:2, explanation:"Timing rules protect critical business windows; they do not remove authorization or shift liability." },
  { id:90256, domain:1, level:2, question:"What is a common purpose of using a jump box or bastion host during authorized internal testing?", options:["To permanently disable the client's firewall so that all subsequent testing proceeds without any filtering","To store the client's most sensitive data in plaintext where every tester can access it without restriction","To automatically exploit any host that connects to it as a normal and expected part of its regular operation","To provide a controlled, monitored access point from which testing traffic can be routed and audited cleanly"], correct:3, explanation:"A jump box gives controlled, auditable access; it is not for disabling firewalls or auto-exploiting hosts." },
  { id:90257, domain:1, level:1, question:"Which best describes 'exfiltration' in the context of a penetration test?", options:["Simulating the unauthorized transfer of data out of the environment to demonstrate potential real-world impact","Importing large amounts of test data into the environment before any of the actual testing work begins here","Rewriting the discovered data into an encrypted archive that is then permanently deleted from every system overall","Physically removing the client's backup tapes from their off-site storage facility during the assessment work"], correct:0, explanation:"Exfiltration simulates unauthorized data transfer out to show impact; it is not importing test data." },
  { id:90258, domain:1, level:2, question:"What is the purpose of including screenshots and command output in a technical report?", options:["To pad the length of the report so it appears more substantial and justifies a higher engagement fee later","To provide clear evidence that supports each finding and helps the client reproduce and verify the results","To legally authorize the exploitation activities that produced the screenshots after the fact during writing","To guarantee that the client's staff will fully understand every deeply technical detail without any effort"], correct:1, explanation:"Evidence like screenshots supports findings and reproducibility; it is not padding or authorization." },
  { id:90259, domain:1, level:3, question:"Why is scope validation important when a client provides a list of target IP addresses?", options:["To ensure the tester is free to add any additional interesting addresses discovered during the engagement for the target","To remove the requirement for a written contract because a validated IP list serves as full legal consent","To confirm the client actually owns or is authorized to permit testing of every address on the provided list","To guarantee that each listed address will be found to contain at least one exploitable vulnerability today"], correct:2, explanation:"Validation confirms ownership and authorization for each address; it does not permit adding new targets." },
  { id:90260, domain:1, level:2, question:"What is the main benefit of the 'assumed breach' testing approach?", options:["It removes the need for any written authorization because the breach is only assumed rather than truly real","It guarantees that the external perimeter will be found to be completely impenetrable during the assessment","It automatically remediates the initial access vulnerability that would have been used to gain the foothold","It saves time by starting from a foothold, letting testers focus on impact, detection, and lateral movement"], correct:3, explanation:"Assumed breach starts from a foothold to focus on impact and detection; it does not remove authorization." },
  { id:90261, domain:1, level:3, question:"What is a primary consideration when testing cloud-hosted assets?", options:["Understanding the shared responsibility model and obtaining any provider-required authorization before testing","Assuming the cloud provider is entirely responsible for every layer, so no client coordination is ever needed","Believing that cloud assets can never be tested at all under any circumstances or with any authorization given","Treating all cloud assets as fully out of scope automatically without ever discussing them with the client"], correct:0, explanation:"Cloud testing requires understanding shared responsibility and provider authorization." },
  { id:90262, domain:1, level:2, question:"Why is 'least privilege' relevant when a tester is granted access for an internal assessment?", options:["The tester should always be granted full domain administrator rights regardless of what the test requires","The tester should receive only the access genuinely needed for the engagement, limiting unnecessary exposure","The tester should be denied all access so that the entire assessment can be performed purely from the outside","The tester should share the granted credentials broadly so that every team member can log in whenever needed"], correct:1, explanation:"Least privilege limits the tester to needed access, reducing exposure; full admin by default is inappropriate." },
  { id:90263, domain:1, level:1, question:"What is the purpose of a kickoff meeting at the start of an engagement?", options:["To immediately begin exploiting the client's most critical systems while the stakeholders are all watching overall","To deliver the completed final report to the client before any of the technical work has actually been done","To align stakeholders on scope, timing, communication, and expectations before any active testing begins now","To publicly announce the engagement to the client's competitors so that they are aware of the testing plans"], correct:2, explanation:"A kickoff aligns stakeholders on scope and expectations before testing; it is not for exploitation." },
  { id:90264, domain:1, level:2, question:"How should a tester treat a finding that is technically valid but has negligible real-world impact?", options:["Inflate its severity to critical so that the overall engagement appears far more valuable to the client in this context","Omit it entirely and never mention it, since low-impact findings have no place in any professional report","Report it as the single most important finding regardless of its actual measured impact on the business","Report it honestly at an appropriately low severity so the client can prioritize their remediation efforts"], correct:3, explanation:"Low-impact findings should be reported honestly at low severity, not inflated or omitted." },
  { id:90265, domain:1, level:3, question:"What is 'threat intelligence' most useful for during engagement planning?", options:["Understanding which threat actors and techniques are most relevant so testing can emulate realistic attacks","Automatically generating the entire final report so the tester never has to document any findings by hand","Legally authorizing the engagement so that no separate signed permission is ever required from the client","Guaranteeing that the tester will discover every vulnerability present in the target environment every time"], correct:0, explanation:"Threat intelligence informs realistic emulation; it does not authorize or auto-report." },
  { id:90266, domain:1, level:2, question:"Why is it important to distinguish between 'in-scope' and 'out-of-scope' findings in a report?", options:["To allow the tester to freely test any out-of-scope system as long as it is later noted within the report","To keep the report focused and to avoid implying that unauthorized systems were tested during the engagement","To transfer all responsibility for out-of-scope systems from the client onto the testing organization itself","To guarantee that every out-of-scope system will automatically be included in the next engagement's scope"], correct:1, explanation:"Distinguishing scope keeps the report focused and avoids implying unauthorized testing occurred." },
  { id:90267, domain:1, level:3, question:"What is a key ethical obligation regarding client data confidentiality after an engagement ends?", options:["Publishing the client's most interesting findings publicly to build the tester's professional reputation fast","Selling the discovered vulnerability details to interested third parties as an additional source of revenue overall","Continuing to protect and properly dispose of client data according to the agreement and applicable regulations","Retaining unencrypted copies of all client data indefinitely for the tester's own convenience going forward"], correct:2, explanation:"Confidentiality obligations continue after the engagement; publishing or selling client data is unethical." },
  { id:90268, domain:1, level:2, question:"What best describes the goal of the 'command and control' tactic in ATT&CK?", options:["Formally authorizing the penetration test in writing before any active testing is permitted to take place now","Producing the executive summary of the final report for the client's non-technical leadership team to review","Physically controlling access to the client's data center by managing the building's badge reader systems","Establishing communication channels an adversary uses to remotely control compromised systems in the network"], correct:3, explanation:"Command and control is about remote control channels for compromised systems, not authorization or reporting." },
  { id:90269, domain:1, level:1, question:"Why should a penetration tester keep client stakeholders informed of critical findings promptly?", options:["So the client can begin urgent remediation quickly rather than waiting until the final report is delivered","So the tester can bill additional hours for each individual notification that is sent to the stakeholders","So the requirement for a written final report is removed once critical findings have been communicated aloud","So the tester can expand the scope automatically each time a new critical finding is reported to the client"], correct:0, explanation:"Prompt notification lets the client remediate urgent issues quickly; it does not remove the report." },
  { id:90270, domain:1, level:2, question:"What is the purpose of defining 'communication channels' in the rules of engagement?", options:["To guarantee that the tester will never need to produce any written report at the end of the engagement","To specify how and to whom the testing team will report progress, issues, and emergencies during the work","To legally authorize the engagement so that no separate signed permission document is required from anyone","To ensure the client's competitors are automatically informed of the testing progress as it happens live"], correct:1, explanation:"Defined communication channels specify reporting and escalation paths; they do not replace the report." },
  { id:90271, domain:1, level:3, question:"What best describes 'initial access' as a tactic in the attack lifecycle?", options:["The final step in which the adversary cleans up all artifacts and exits the compromised environment quietly","The reporting stage in which the tester documents all findings for the client's leadership team to review","The techniques an adversary uses to gain their first foothold within a target environment, such as phishing","The pre-engagement stage in which the scope and rules of engagement are agreed between the two parties involved"], correct:2, explanation:"Initial access is gaining the first foothold; cleanup and reporting are later stages." },
  { id:90272, domain:1, level:2, question:"What is the purpose of 'timestomping' as a defense evasion technique?", options:["Synchronizing all of the host's clocks precisely so that log entries are perfectly aligned across systems","Speeding up a scan by reducing the time spent probing each individual port on the target host being scanned","Recording the exact time each finding was discovered so the final report has an accurate detailed timeline","Altering the timestamps on files so that malicious changes blend in with legitimate activity on the host"], correct:3, explanation:"Timestomping alters file timestamps to hide changes; it is not clock synchronization." },
  { id:90273, domain:1, level:3, question:"Which best describes a 'watering hole' attack?", options:["Compromising a website the target group frequently visits so that victims are infected when they browse it","Flooding a target server with traffic until it becomes unavailable to all of its legitimate users at once","Sending a personalized email to a single high-value executive to trick them into revealing their password","Physically following an employee through a secured door to gain unauthorized access to a restricted area in this context"], correct:0, explanation:"A watering hole compromises a commonly visited site; flooding a server is a denial-of-service attack." },
  { id:90274, domain:1, level:2, question:"What does 'tailgating' refer to in physical security testing?", options:["Sending a fraudulent email that appears to come from a trusted internal colleague inside the organization","Following an authorized person through a secure door to gain entry without presenting valid credentials","Overwhelming a web application with automated requests until it can no longer respond to real users at all","Capturing wireless traffic from a parking lot to recover the pre-shared key of the corporate network here"], correct:1, explanation:"Tailgating is following someone through a secure door; the email option describes phishing instead." },
  { id:90275, domain:1, level:1, question:"Why is a signed scope agreement preferable to a verbal agreement?", options:["It guarantees that the tester will discover every vulnerability that exists within the target environment","It automatically renews the engagement each year without any further discussion between the two parties in this context","It provides clear, enforceable documentation of what was authorized, protecting both the tester and client","It removes the requirement to produce a written report because the agreement already documents everything"], correct:2, explanation:"A signed agreement is enforceable documentation protecting both parties; verbal terms are hard to prove." },
  { id:90276, domain:1, level:2, question:"What is the primary role of a 'proxy' tool like Burp during web testing?", options:["To crack the password hashes captured from the web application's backend database in a fully offline manner","To scan the target's network for open ports and to fingerprint the operating systems of discovered hosts","To generate the final penetration test report automatically once the web assessment has been completed","To intercept, inspect, and modify HTTP requests and responses between the browser and the web application"], correct:3, explanation:"A proxy intercepts and modifies web traffic; port scanning is Nmap's role, not Burp's primary function." },
  { id:90277, domain:1, level:3, question:"What is 'spear phishing' compared to general phishing?", options:["A targeted phishing attack tailored to a specific individual or organization using personalized information","A phishing attack that is sent randomly to millions of recipients with no personalization whatsoever at all","A physical attack in which the tester breaks a window to gain entry into the organization's main office","A network attack that floods the mail server with traffic until it can no longer deliver any messages here"], correct:0, explanation:"Spear phishing is targeted and personalized; general phishing is broad and untargeted." },
  { id:90278, domain:1, level:2, question:"Why should a tester document assumptions made during an engagement?", options:["So the tester can legally justify testing any system at all without ever obtaining written authorization","So the client understands the context and limitations behind each finding and can interpret results correctly","So the report is long enough to justify charging the client a substantially higher fee for the engagement","So the client is prevented from ever asking any follow-up questions about the findings after delivery in this context"], correct:1, explanation:"Documenting assumptions gives context and limitations for findings; it does not replace authorization." },
  { id:90279, domain:1, level:3, question:"What is the main purpose of the 'delivery' step in an intrusion lifecycle?", options:["Physically delivering the final printed report to the client's office at the end of the engagement period","Handing over the signed authorization letter to the client before any of the testing activities begin at all","Transmitting the weaponized payload to the target, for example via email attachment, link, or removable media","Delivering a presentation to the client's leadership summarizing the business impact of all the findings in this context"], correct:2, explanation:"Delivery transmits the weaponized payload to the target; it is not report or authorization delivery." },
  { id:90280, domain:1, level:2, question:"Which is an example of a 'physical' penetration testing technique?", options:["Sending crafted HTTP requests to a web application in order to fingerprint its underlying software stack","Running an Nmap scan against a public IP range to enumerate the internet-facing services of a target host","Cracking captured WPA2 handshakes offline using a wordlist and a high-performance graphics processing unit","Attempting to bypass door locks or badge readers to gain unauthorized entry to a restricted facility area"], correct:3, explanation:"Bypassing locks or badge readers is physical testing; the others are network or wireless techniques." },
  { id:90281, domain:1, level:1, question:"What is 'dumpster diving' in the reconnaissance context?", options:["Searching discarded materials such as printouts and media for sensitive information useful to an attacker","Running an aggressive port scan against every host on the target network as quickly as possible in one pass","Intercepting and modifying the HTTP traffic of a web application using an intercepting proxy during testing","Brute-forcing an online login form by trying thousands of password combinations against a single account"], correct:0, explanation:"Dumpster diving searches discarded materials for sensitive info; the others are technical techniques." },
  { id:90282, domain:1, level:3, question:"Why is it important to have a rollback or recovery plan before intrusive testing?", options:["So that the tester can guarantee that no vulnerabilities will ever be discovered during the engagement work","So that any accidental disruption to systems can be reversed quickly to restore normal client operations","So that the requirement for written client authorization can be waived for the intrusive testing activities","So that the client's competitors are automatically notified whenever a critical system is affected by testing"], correct:1, explanation:"A rollback plan enables quick recovery from disruption; it does not waive authorization." },
  { id:90283, domain:1, level:3, question:"What is the significance of the 'need to know' principle when sharing test results?", options:["Every employee in the organization must receive the full technical report regardless of their role or need","The findings must be published publicly so the entire security community can benefit from the results here","Sensitive findings should be shared only with individuals who require them, limiting unnecessary disclosure","The tester should keep all findings entirely secret and never share them with anyone at the client at all for the target"], correct:2, explanation:"Need to know limits disclosure of sensitive findings to those who require them." },
  { id:90284, domain:1, level:3, question:"What does 'privilege escalation' via a misconfigured service typically exploit?", options:["A perfectly configured service that follows least privilege and offers no avenue for any escalation at all","A network cable that has been physically disconnected from the switch during the engagement by the tester","A signed legal document that authorizes the tester to perform the assessment against the target environment","A service running with excessive permissions that can be abused to gain higher-level access on the system"], correct:3, explanation:"Escalation abuses over-privileged or misconfigured services; a least-privilege service offers no avenue." },
  { id:90285, domain:1, level:3, question:"Why is continuous scope confirmation valuable during a long engagement?", options:["Environments and ownership can change, so periodic confirmation keeps testing within authorized boundaries","It guarantees the tester will find more vulnerabilities the longer the engagement is allowed to continue","It removes the need for a final report because the scope confirmations already document all of the findings","It automatically transfers responsibility for any newly added systems onto the testing organization itself"], correct:0, explanation:"Ongoing scope confirmation keeps testing authorized as environments change." },
  { id:90286, domain:1, level:3, question:"What is the main goal of 'reconnaissance' in the MITRE ATT&CK framework?", options:["Cleaning up artifacts left on compromised systems so that defenders cannot trace the intrusion afterward","Gathering information the adversary can use to plan future operations against the chosen target organization","Producing the final written report that summarizes findings for the client's leadership team to review later","Formally signing the engagement authorization document before any active testing activity is permitted at all"], correct:1, explanation:"ATT&CK reconnaissance is information gathering to plan operations, not cleanup or reporting." },
  { id:90287, domain:1, level:1, question:"Why should a tester validate that a target is actually owned by the client before scanning?", options:["Scanning always requires the tester to first exploit the target before ownership can be reliably confirmed","Ownership validation guarantees that every scanned host will contain at least one exploitable vulnerability","Scanning systems the client does not own may be unauthorized and could expose the tester to legal liability","Ownership validation removes the need for any written authorization once the client's ownership is confirmed"], correct:2, explanation:"Scanning non-owned systems can be unauthorized; validation prevents legal exposure." },
  { id:90288, domain:1, level:3, question:"What is the purpose of a 'gap analysis' following a penetration test?", options:["Measuring the physical distance between the client's various office buildings for logistics planning purposes","Automatically remediating every finding from the report without any action required by the client at all","Transferring ownership of all identified vulnerabilities from the client onto the testing organization now","Comparing current security posture against desired standards to identify where improvements are most needed"], correct:3, explanation:"Gap analysis compares posture to standards to guide improvement; it does not auto-remediate." },
  { id:90289, domain:1, level:3, question:"What best describes 'credential harvesting'?", options:["Collecting usernames and passwords, for example via phishing or memory scraping, to enable further access","Generating brand-new strong passwords for every user account to improve the organization's overall security","Deleting all stored credentials from a compromised host so that no one can ever log in to it again at all","Physically collecting employee badges from a reception desk to return them to their rightful owners later"], correct:0, explanation:"Credential harvesting collects usernames and passwords for further access; it is not password generation." },
  { id:90290, domain:1, level:3, question:"Why is it useful to categorize findings by CWE in a report?", options:["It legally authorizes the exploitation of each categorized finding without any client permission required","It links findings to common weakness types, helping developers understand and address root causes broadly","It guarantees that the categorized weaknesses can never be reintroduced into the codebase in the future","It replaces the executive summary because a list of weakness categories is all leadership ever needs to see"], correct:1, explanation:"CWE categorization helps address root causes; it does not authorize or replace the summary." },
  { id:90291, domain:1, level:3, question:"What is the primary reason to encrypt a penetration test report in transit and at rest?", options:["Encryption automatically remediates every vulnerability that is described within the pages of the report","Encryption legally authorizes the engagement so no separate signed permission is needed from the client in this context","The report contains sensitive vulnerability details that could aid a real attacker if intercepted or exposed","Encryption guarantees that the client will remediate all findings within a strict and fixed set timeframe"], correct:2, explanation:"Reports hold sensitive vuln details that must be protected; encryption does not remediate anything." },
  { id:90292, domain:1, level:3, question:"What is 'OSINT framework' tooling primarily used for?", options:["Automatically exploiting every vulnerability discovered during the active phase of the engagement at once","Cracking captured password hashes offline using large wordlists and specialized graphics hardware acceleration","Intercepting and modifying live HTTP traffic between a browser and a target web application during testing","Organizing and accessing many public data sources to efficiently gather intelligence about a target entity"], correct:3, explanation:"OSINT frameworks organize public data sources for intelligence gathering; they do not exploit or crack hashes." },
  { id:90293, domain:1, level:1, question:"Why should testers be cautious with destructive payloads even when in scope?", options:["Destructive actions can cause unintended data loss or downtime, so their use should be deliberate and approved","Destructive payloads are the only reliable way to accurately measure a system's true security posture today","Destructive payloads automatically end the tester's legal liability for anything that happens afterward now","Destructive payloads are always expected by clients as convincing proof that the assessment was thorough in this context"], correct:0, explanation:"Destructive payloads risk data loss and downtime; their use must be deliberate and approved." },
  { id:90294, domain:1, level:1, question:"What is the value of correlating findings across multiple hosts in a report?", options:["It legally authorizes testing of any additional hosts that were discovered during the correlation process","It reveals systemic issues and attack paths that individual host findings might not make obvious on their own","It guarantees that every correlated host will be fully patched by the client within a fixed set timeframe","It removes the requirement for an executive summary because correlated findings speak for themselves entirely"], correct:1, explanation:"Correlation reveals systemic issues and attack paths across hosts." },
  { id:90295, domain:1, level:1, question:"What is a key reason to test authentication mechanisms during an assessment?", options:["Authentication testing is the only method capable of detecting the operating system of a remote target host","Authentication testing automatically strengthens every password in the environment as it is being performed","Weak or broken authentication can allow attackers to bypass access controls and impersonate legitimate users","Authentication testing legally authorizes the entire engagement so no signed client permission is required overall"], correct:2, explanation:"Weak authentication lets attackers bypass access controls; testing does not auto-strengthen passwords." },
  { id:90296, domain:1, level:1, question:"Why is it important to define acceptable testing techniques in the rules of engagement?", options:["So the tester is free to use any technique at any time regardless of what the client may have requested","So the requirement for a written final report is removed once the technique list has been fully agreed upon","So the client's competitors are automatically informed of every technique the tester intends to eventually use","So both parties agree on which methods, such as social engineering or DoS, are permitted or prohibited here"], correct:3, explanation:"Defining acceptable techniques sets what methods are permitted or prohibited; it does not remove reporting." },
  { id:90297, domain:1, level:1, question:"What best describes the role of a 'debrief' or 'read-out' session?", options:["Presenting and discussing the findings with the client so they understand the risks and remediation options","Renegotiating the entire engagement contract price after all of the technical testing has been completed now","Publicly disclosing the client's vulnerabilities before the client has had any opportunity to remediate them","Transferring legal ownership of every discovered vulnerability from the client onto the testing organization"], correct:0, explanation:"A read-out presents and discusses findings with the client; it is not for public disclosure." },
  { id:90298, domain:1, level:1, question:"Why is it useful to include a methodology section in the final report?", options:["It legally authorizes the engagement so no separate signed permission is required from the client beforehand","It documents the approach and standards followed, giving the client confidence in the rigor of the assessment","It guarantees that no vulnerabilities were missed anywhere in the environment during the assessment work in this context","It automatically remediates each finding described elsewhere in the report without any client action needed"], correct:1, explanation:"A methodology section documents the approach and builds confidence; it does not authorize or remediate." },
  { id:90299, domain:1, level:1, question:"What is the purpose of 'retest' or 'validation' engagements after remediation?", options:["To discover an entirely new and unrelated set of vulnerabilities outside of the original engagement scope","To renegotiate the contract price now that the client has already reviewed the initial set of findings here","To independently confirm that reported issues are resolved and that fixes did not introduce new problems","To transfer ownership of any remaining vulnerabilities from the client onto the testing organization itself"], correct:2, explanation:"Retests confirm fixes work and did not break anything new; they are not for scope expansion." },
  { id:90300, domain:1, level:1, question:"What is a core professional responsibility when a client disputes a finding?", options:["Immediately remove every disputed finding without any review, since the client is always entirely correct","Refuse to discuss the finding at all and insist the report stands exactly as written no matter what evidence","Escalate the dispute publicly on social media so that the wider security community can weigh in on it too","Provide the supporting evidence and reasoning objectively, and correct the report if the dispute is valid"], correct:3, explanation:"Professionalism means providing evidence objectively and correcting genuine errors; not blind removal or refusal." },
];
